import React, { useState, useEffect } from 'react';
import './App.css';

interface Deployment {
  customer: string;
  project: string;
  environment: string;
  branch: string;
  commit: string;
  user: string;
  email: string;
  releaseDate: string;
  buildDate: string;
}

interface ApiResponse {
  pageNumber: number;
  pageSize: number;
  total: number;
  results: Deployment[];
}

type Environment = 'PROD' | 'STAGE' | 'TEST';

function App() {
  const [deployments, setDeployments] = useState<Deployment[]>([]);
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedEnv, setSelectedEnv] = useState<Environment>('PROD');

  // Funzione per chiamare l'API
  const fetchDeployments = async (env: Environment) => {
    try {
      setLoading(true);
      setError(null);

      const response = await fetch(`https://release-tracking-api.keros-digital.com/release/all/${env}`);

      if (!response.ok) {
        throw new Error(`Errore HTTP: ${response.status}`);
      }

      const data: ApiResponse = await response.json();
      setDeployments(data.results);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Errore sconosciuto');
      console.error('Errore nel recupero dati:', err);
    } finally {
      setLoading(false);
    }
  };

  // Carica i dati iniziali
  useEffect(() => {
    fetchDeployments(selectedEnv);
  }, []);

  // Gestisce il cambio di ambiente
  const handleEnvChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
    const newEnv = event.target.value as Environment;
    setSelectedEnv(newEnv);
    fetchDeployments(newEnv);
  };

  // Formatta la data per renderla più leggibile
  const formatDate = (dateString: string) => {
    if (dateString === '0001-01-01T00:00:00') return '-';
    const date = new Date(dateString);
    return date.toLocaleDateString('it-IT', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  // Tag colorato per l'ambiente
  const getEnvironmentBadge = (env: string) => {
    const colors: Record<string, string> = {
      PROD: '#dc3545',
      STAGE: '#ffc107',
      TEST: '#28a745'
    };
    return colors[env] || '#6c757d';
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>🚀 Deploy Tracker</h1>
        <div className="controls">
          <label htmlFor="env-select">Ambiente:</label>
          <select 
            id="env-select" 
            value={selectedEnv} 
            onChange={handleEnvChange}
            disabled={loading}
          >
            <option value="PROD">PROD</option>
            <option value="STAGE">STAGE</option>
            <option value="TEST">TEST</option>
          </select>
          <button 
            onClick={() => fetchDeployments(selectedEnv)} 
            disabled={loading}
            className="refresh-btn"
          >
            {loading ? 'Caricamento...' : 'Aggiorna'}
          </button>
        </div>
      </header>

      <main className="App-main">
        {!loading && !error && (
          <div className="stats">
            <span>Mostrati: {deployments.length} / Totali: {deployments.length}</span>
          </div>
        )}

        {loading && <div className="loading">Caricamento dati...</div>}

        {error && <div className="error">❌ Errore: {error}</div>}

        {!loading && !error && deployments.length === 0 && (
          <div className="no-data">Nessun deployment trovato per {selectedEnv}</div>
        )}

        {!loading && !error && deployments.length > 0 && (
          <table className="deployment-table">
            <thead>
              <tr>
                <th>Cliente</th>
                <th>Progetto</th>
                <th>Ambiente</th>
                <th>Branch</th>
                <th>Commit</th>
                <th>Deployer</th>
                <th>Data Release</th>
              </tr>
            </thead>
            <tbody>
              {deployments.map((dep, index) => (
                <tr key={index}>
                  <td>{dep.customer}</td>
                  <td>{dep.project}</td>
                  <td>
                    <span 
                      className="badge"
                      style={{ backgroundColor: getEnvironmentBadge(dep.environment) }}
                    >
                      {dep.environment}
                    </span>
                  </td>
                  <td>{dep.branch}</td>
                  <td className="commit">{dep.commit.substring(0, 7)}</td>
                  <td>{dep.user}</td>
                  <td>{formatDate(dep.releaseDate)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </main>
    </div>
  );
}

export default App;
